#include <bits/stdc++.h>
using namespace std;
priority_queue<long long,vector<long long>,greater<long long> > a;
int main(){
    long long n,ans=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        int t;
        cin>>t;
        a.push(t);
    }
    for(int i=1;i<n;i++){
        long long x,y;
        x=a.top(),a.pop(),y=a.top(),a.pop();
        a.push(x+y),ans+=x+y;
    }
    cout<<ans;
    return 0;
}
